"use client";

import React, {
  useState,
  useRef,
  useEffect,
  useCallback,
  useMemo,
  createContext,
  useContext,
  forwardRef,
  cloneElement,
} from "react";
import type { CSSProperties, ReactNode } from "react";
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationLink,
  PaginationPrevious,
  PaginationNext,
  PaginationEllipsis,
} from "@/components/ui/pagination";

const ROW_STATUS = {
  DEFAULT: "default",
  NEW: "new",
  EDITING: "editing",
  TEMPORARY: "temporary",
} as const;

type RowStatusType = (typeof ROW_STATUS)[keyof typeof ROW_STATUS];

interface ActionColumnRenderOptions<T> {
  status: "default" | "new" | "editing";
  onRemove: (row: T) => void;
  onSave: (row: T) => void;
  onCancel: (row: T) => void;
  onEdit: (row: T) => void;
}

interface STableColumnProps<T = any> {
  title?: ReactNode;
  dataIndex?: string;
  key?: string;
  width?: number | string;
  fixed?: "left" | "right";
  align?: "left" | "center" | "right";
  render?: (value: any, record: T, index: number) => ReactNode;
  resizable?: boolean;
  editable?: boolean;
  editorRules?: any[];
  editor?: ReactNode;
  sorter?: (a: T, b: T) => number;
  children?: STableColumnProps<T>[];
}

interface STableProps<T = any> {
  columns?: STableColumnProps<T>[];
  data?: T[];
  defaultData?: T[];
  rowKey?: string | ((record: T) => string);
  borderCell?: boolean;
  stripe?: boolean;
  hover?: boolean;
  loading?: boolean;
  noDataElement?: ReactNode;
  pagination?: false | { pageSize?: number; current?: number; total?: number };
  scroll?: { x?: number | string; y?: number | string };
  style?: CSSProperties;
  className?: string;
  resizable?: boolean;
  addRowBtn?: ReactNode | boolean;
  addRowBtnText?: string;
  addRowBtnIcon?: ReactNode;
  maxDataLength?: number;
  showActionColumn?: boolean | ReactNode;
  actionColumnFixed?: "left" | "right";
  actionColumnTitle?: string;
  actionColumnRender?: (
    row: T,
    options: ActionColumnRenderOptions<T>
  ) => ReactNode;
  onRowAdd?: (data: T[]) => void;
  onRowRemove?: (data: T[], removedRow: T) => void;
  onRowSave?: (data: T[], savedRow: T) => void;
  onRowCancel?: (data: T[], canceledRow: T) => void;
  onRowEdit?: (data: T[], editingRow: T) => void;
  onChange?: (...args: any[]) => void;
  onResizeStop?: (
    currentColumn: STableColumnProps,
    columns: STableColumnProps[]
  ) => void;
}

interface FormContextValue {
  values: Record<string, any>;
  setFieldValue: (field: string, value: any) => void;
  getValues: () => Record<string, any>;
  validate: (
    fields?: string[],
    callback?: (
      errors: Record<string, string> | null,
      values: Record<string, any>
    ) => void
  ) => void;
  rules: Record<string, any[]>;
  setRules: (field: string, rules: any[]) => void;
}

const FormContext = createContext<FormContextValue>({
  values: {},
  setFieldValue: () => {},
  getValues: () => ({}),
  validate: () => {},
  rules: {},
  setRules: () => {},
});

function useFormContext() {
  return useContext(FormContext);
}

function TextButton({
  onClick,
  disabled,
  children,
}: {
  onClick?: (e: React.MouseEvent) => void;
  disabled?: boolean;
  children: ReactNode;
}) {
  return (
    <span
      style={{
        color: disabled
          ? "var(--color-text-4)"
          : "rgb(var(--primary-6))",
        fontSize: 12,
        cursor: disabled ? "default" : "pointer",
        marginRight: 12,
      }}
      onClick={(e) => {
        if (!disabled && onClick) onClick(e);
      }}
    >
      {children}
    </span>
  );
}

function PlusCircleIcon() {
  return (
    <svg
      width="14"
      height="14"
      viewBox="0 0 48 48"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      style={{ marginRight: 6, verticalAlign: "middle" }}
    >
      <path
        d="M24 44c11.046 0 20-8.954 20-20S35.046 4 24 4 4 12.954 4 24s8.954 20 20 20Z"
        fill="none"
        stroke="currentColor"
        strokeWidth="3"
      />
      <path
        d="M24 16v16M16 24h16"
        stroke="currentColor"
        strokeWidth="3"
        strokeLinecap="round"
      />
    </svg>
  );
}

function AddRowButton({
  customBtn,
  text,
  icon,
  disabled,
  onAddRow,
}: {
  customBtn?: ReactNode;
  text?: string;
  icon?: ReactNode;
  disabled?: boolean;
  onAddRow?: () => void;
}) {
  if (customBtn) {
    return <div style={{ marginTop: 12 }}>{customBtn}</div>;
  }
  return (
    <div style={{ marginTop: 12 }}>
      <button
        disabled={disabled}
        onClick={onAddRow}
        style={{
          width: "100%",
          height: 32,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          gap: 4,
          border: "1px dashed var(--color-border-2)",
          borderRadius: "var(--border-radius-small)",
          background: "var(--color-bg-4)",
          color: disabled
            ? "var(--color-text-4)"
            : "var(--color-text-2)",
          fontSize: 14,
          cursor: disabled ? "not-allowed" : "pointer",
          transition: "all 0.2s",
        }}
        onMouseEnter={(e) => {
          if (!disabled) {
            e.currentTarget.style.borderColor = "rgb(var(--primary-6))";
            e.currentTarget.style.color = "rgb(var(--primary-6))";
          }
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.borderColor = "var(--color-border-2)";
          e.currentTarget.style.color = disabled
            ? "var(--color-text-4)"
            : "var(--color-text-2)";
        }}
      >
        {icon ?? <PlusCircleIcon />}
        {text || "添加一行"}
      </button>
    </div>
  );
}

function SaveWrapper({
  render,
}: {
  render: (
    handleSave: (onSave: (row: any) => void, rowData: any) => void
  ) => ReactNode;
}) {
  const form = useFormContext();
  const handleSave = (onSave: (row: any) => void, rowData: any) => {
    form.validate(undefined, (errors, values) => {
      if (!errors) {
        onSave({ ...rowData, ...values });
      }
    });
  };
  return <>{render(handleSave)}</>;
}

const ResizeHandle = forwardRef<HTMLDivElement, any>((props, ref) => {
  const {
    height,
    visible,
    highlight,
    index,
    handleAxis: _ha,
    disabled = false,
    ...restProps
  } = props;
  return (
    <div
      ref={ref}
      style={{
        position: "absolute",
        width: 12,
        height: height,
        top: 0,
        right: -7,
        cursor: "col-resize",
        visibility: !disabled && visible ? "visible" : "hidden",
        opacity: !disabled && highlight ? 1 : 0,
        transition: "opacity 0.1s ease",
        zIndex: 10,
      }}
      {...restProps}
      data-index={index}
      onClick={(e) => e.stopPropagation()}
    >
      <div
        style={{
          width: 2,
          height: "100%",
          marginLeft: 5,
          backgroundColor: "rgb(var(--primary-6))",
        }}
      />
    </div>
  );
});
ResizeHandle.displayName = "ResizeHandle";

function EditableCell({
  children,
  rowData,
  column,
  onSave,
  rowStatus,
}: {
  children: ReactNode;
  rowData: any;
  column: STableColumnProps;
  onSave?: (row: any, fromCell?: boolean) => void;
  rowStatus?: string;
}) {
  const form = useFormContext();
  const ref = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const isStatusEditing =
    rowStatus === ROW_STATUS.NEW || rowStatus === ROW_STATUS.EDITING;
  const [editing, setEditing] = useState(isStatusEditing);

  useEffect(() => {
    if (isStatusEditing && !editing) {
      setEditing(true);
    } else if (rowStatus === ROW_STATUS.DEFAULT && editing) {
      setEditing(false);
    }
  }, [rowStatus]);

  useEffect(() => {
    if (editing && column.dataIndex) {
      form.setFieldValue(column.dataIndex, rowData[column.dataIndex]);
      if (column.editorRules) {
        form.setRules(column.dataIndex, column.editorRules);
      }
    }
  }, [editing]);

  useEffect(() => {
    if (editing && inputRef.current) {
      inputRef.current.focus();
    }
  }, [editing]);

  const handleValueSave = useCallback(() => {
    if (rowData.__STATUS) return;
    const values = form.getValues();
    form.validate(
      column.dataIndex ? [column.dataIndex] : undefined,
      (errors) => {
        if (!errors || (column.dataIndex && !errors[column.dataIndex])) {
          setEditing(false);
          onSave?.({ ...rowData, ...values }, true);
        }
      }
    );
  }, [rowData, column, form, onSave]);

  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (
        editing &&
        column.editable &&
        !rowData.__STATUS &&
        ref.current &&
        !ref.current.contains(e.target as Node)
      ) {
        setTimeout(() => handleValueSave(), 30);
      }
    };
    document.addEventListener("click", handleClick, true);
    return () => document.removeEventListener("click", handleClick, true);
  }, [editing, rowData, column, handleValueSave]);

  if (editing && column.editable) {
    const fieldName = column.dataIndex || "";
    return (
      <div ref={ref}>
        {column.editor ? (
          cloneElement(column.editor as any, {
            ref: inputRef,
            value: form.values[fieldName] ?? "",
            onChange: (e: any) => {
              const val = e?.target?.value ?? e;
              form.setFieldValue(fieldName, val);
            },
            onKeyDown: (e: React.KeyboardEvent) => {
              if (e.key === "Enter") handleValueSave();
            },
            style: {
              width: "100%",
              height: 30,
              padding: "4px 8px",
              border: "1px solid rgb(var(--primary-6))",
              borderRadius: "var(--border-radius-small)",
              outline: "none",
              fontSize: 14,
              boxSizing: "border-box" as const,
            },
          })
        ) : (
          <input
            ref={inputRef}
            value={form.values[fieldName] ?? ""}
            onChange={(e) => form.setFieldValue(fieldName, e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleValueSave();
            }}
            style={{
              width: "100%",
              height: 30,
              padding: "4px 8px",
              border: "1px solid rgb(var(--primary-6))",
              borderRadius: "var(--border-radius-small)",
              outline: "none",
              fontSize: 14,
              boxSizing: "border-box",
            }}
          />
        )}
      </div>
    );
  }

  return (
    <div
      style={{
        boxSizing: "border-box",
        padding: "6px 12px",
        minHeight: 32,
        cursor: column.editable && !rowData.__STATUS ? "pointer" : "default",
        border: "1px solid transparent",
        borderRadius: "var(--border-radius-small)",
        transition: "border-color 0.2s",
      }}
      onClick={() => {
        if (!rowData.__STATUS && column.editable) setEditing(true);
      }}
      onMouseEnter={(e) => {
        if (column.editable && !rowData.__STATUS) {
          e.currentTarget.style.borderColor = "var(--color-border-2)";
        }
      }}
      onMouseLeave={(e) => {
        if (column.editable && !rowData.__STATUS) {
          e.currentTarget.style.borderColor = "transparent";
        }
      }}
    >
      {children}
    </div>
  );
}

function FormProvider({
  children,
  initialValues,
}: {
  children: ReactNode;
  initialValues?: Record<string, any>;
}) {
  const [values, setValues] = useState<Record<string, any>>(
    initialValues || {}
  );
  const [rules, setRulesState] = useState<Record<string, any[]>>({});

  const setFieldValue = useCallback((field: string, value: any) => {
    setValues((prev) => ({ ...prev, [field]: value }));
  }, []);

  const getValues = useCallback(() => values, [values]);

  const setRules = useCallback((field: string, fieldRules: any[]) => {
    setRulesState((prev) => ({ ...prev, [field]: fieldRules }));
  }, []);

  const validate = useCallback(
    (
      fields?: string[],
      callback?: (
        errors: Record<string, string> | null,
        values: Record<string, any>
      ) => void
    ) => {
      const fieldsToValidate = fields || Object.keys(rules);
      let hasErrors = false;
      const errors: Record<string, string> = {};

      fieldsToValidate.forEach((field) => {
        const fieldRules = rules[field] || [];
        fieldRules.forEach((rule: any) => {
          if (rule.required && !values[field]) {
            errors[field] = rule.message || `${field} is required`;
            hasErrors = true;
          }
        });
      });

      callback?.(hasErrors ? errors : null, values);
    },
    [rules, values]
  );

  const ctx = useMemo(
    () => ({ values, setFieldValue, getValues, validate, rules, setRules }),
    [values, setFieldValue, getValues, validate, rules, setRules]
  );

  return <FormContext.Provider value={ctx}>{children}</FormContext.Provider>;
}

function getRowKey<T>(record: T, rowKeyProp?: string | ((r: T) => string)): string {
  if (typeof rowKeyProp === "function") return rowKeyProp(record);
  if (typeof rowKeyProp === "string") return (record as any)[rowKeyProp];
  return (record as any).key ?? String(Math.random());
}

function getLeafColumns<T>(columns: STableColumnProps<T>[]): STableColumnProps<T>[] {
  const leaves: STableColumnProps<T>[] = [];
  const traverse = (cols: STableColumnProps<T>[]) => {
    cols.forEach((col) => {
      if (col.children && col.children.length > 0) {
        traverse(col.children);
      } else {
        leaves.push(col);
      }
    });
  };
  traverse(columns);
  return leaves;
}

type HeaderCellMeta<T> = {
  col: STableColumnProps<T>;
  colSpan: number;
  rowSpan: number;
  startLeafIndex: number;
  endLeafIndex: number;
};

function getHeaderRows<T>(columns: STableColumnProps<T>[]): HeaderCellMeta<T>[][] {
  const maxDepth = getMaxDepth(columns);
  const rows: HeaderCellMeta<T>[][] = [];
  for (let i = 0; i < maxDepth; i++) rows.push([]);

  const fill = (
    cols: STableColumnProps<T>[],
    depth: number,
    startLeafIndex: number
  ) => {
    let currentLeafIndex = startLeafIndex;
    cols.forEach((col) => {
      const leafCount = getLeafCount(col);
      if (col.children && col.children.length > 0) {
        rows[depth].push({
          col,
          colSpan: leafCount,
          rowSpan: 1,
          startLeafIndex: currentLeafIndex,
          endLeafIndex: currentLeafIndex + leafCount - 1,
        });
        fill(col.children, depth + 1, currentLeafIndex);
      } else {
        rows[depth].push({
          col,
          colSpan: 1,
          rowSpan: maxDepth - depth,
          startLeafIndex: currentLeafIndex,
          endLeafIndex: currentLeafIndex,
        });
      }
      currentLeafIndex += leafCount;
    });
  };
  fill(columns, 0, 0);
  return rows;
}

function getMaxDepth<T>(columns: STableColumnProps<T>[]): number {
  let max = 1;
  columns.forEach((col) => {
    if (col.children && col.children.length > 0) {
      max = Math.max(max, 1 + getMaxDepth(col.children));
    }
  });
  return max;
}

function getLeafCount<T>(col: STableColumnProps<T>): number {
  if (!col.children || col.children.length === 0) return 1;
  return col.children.reduce((sum, c) => sum + getLeafCount(c), 0);
}

function EditableRow({
  children,
  record,
  columns,
}: {
  children: ReactNode;
  record: any;
  columns: STableColumnProps[];
}) {
  const initialValues: Record<string, any> = {};
  columns.forEach((col) => {
    if (col.dataIndex) {
      initialValues[col.dataIndex] = record[col.dataIndex];
    }
  });
  return (
    <FormProvider initialValues={initialValues}>
      <tr
        style={{
          transition: "background 0.2s",
        }}
      >
        {children}
      </tr>
    </FormProvider>
  );
}

function getPageNumbers(current: number, total: number): (number | "ellipsis")[] {
  if (total <= 7) return Array.from({ length: total }, (_, i) => i + 1);
  const pages: (number | "ellipsis")[] = [1];
  if (current > 3) pages.push("ellipsis");
  const start = Math.max(2, current - 1);
  const end = Math.min(total - 1, current + 1);
  for (let i = start; i <= end; i++) pages.push(i);
  if (current < total - 2) pages.push("ellipsis");
  pages.push(total);
  return pages;
}

function STable<T extends Record<string, any> = any>(props: STableProps<T>) {
  const {
    columns = [],
    data: propData,
    defaultData,
    rowKey = "key",
    borderCell = true,
    stripe = false,
    hover = true,
    loading = false,
    noDataElement,
    scroll,
    style,
    className,
    resizable = false,
    addRowBtn,
    addRowBtnText,
    addRowBtnIcon,
    maxDataLength,
    showActionColumn = false,
    actionColumnFixed,
    actionColumnTitle,
    actionColumnRender,
    onRowAdd,
    onRowRemove,
    onRowSave,
    onRowCancel,
    pagination,
    onRowEdit,
    onResizeStop,
  } = props;

  const [innerData, setInnerData] = useState<any[]>(() => {
    return (propData || defaultData || []).map((item: any) =>
      showActionColumn
        ? { ...item, __STATUS: ROW_STATUS.DEFAULT }
        : { ...item }
    );
  });

  useEffect(() => {
    if (propData) {
      setInnerData((prev) => {
        return propData.map((item: any) => {
          const stateItem = prev.find(
            (d: any) => getRowKey(d, rowKey) === getRowKey(item, rowKey)
          );
          let status: string;
          if (item.__STATUS) {
            status = item.__STATUS;
          } else if (
            !stateItem ||
            stateItem.__STATUS === ROW_STATUS.TEMPORARY
          ) {
            status = ROW_STATUS.NEW;
          } else if (!stateItem.__STATUS) {
            status = ROW_STATUS.DEFAULT;
          } else {
            status = stateItem.__STATUS;
          }
          return showActionColumn
            ? { ...item, __STATUS: status }
            : { ...item };
        });
      });
    }
  }, [propData, showActionColumn]);

  const [columnWidths, setColumnWidths] = useState<Record<string, number>>({});
  const [resizeHighlight, setResizeHighlight] = useState<number | null>(null);
  const [resizerVisible, setResizerVisible] = useState(false);
  const tableRef = useRef<HTMLDivElement>(null);
  const [hoverRow, setHoverRow] = useState<string | null>(null);

  const paginationEnabled = pagination !== false;
  const pageSize =
    (typeof pagination === "object" && pagination?.pageSize) || 10;
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    if (typeof pagination === "object" && pagination?.current !== undefined) {
      setCurrentPage(pagination.current);
    }
  }, [pagination]);

  useEffect(() => {
    if (paginationEnabled) {
      const maxPage = Math.max(1, Math.ceil(innerData.length / pageSize));
      if (currentPage > maxPage) {
        setCurrentPage(maxPage);
      }
    }
  }, [innerData.length, pageSize, paginationEnabled]);

  const totalItems =
    typeof pagination === "object" && pagination?.total !== undefined
      ? pagination.total
      : innerData.length;
  const totalPages = Math.ceil(totalItems / pageSize);
  const showPagination = paginationEnabled && totalItems > pageSize;

  const paginatedData = showPagination
    ? innerData.slice(
        (currentPage - 1) * pageSize,
        currentPage * pageSize
      )
    : innerData;

  const getPureData = useCallback(
    (statusData: any) => {
      if (Array.isArray(statusData)) {
        return statusData.map((item: any) => {
          const d = { ...item };
          delete d.__STATUS;
          return d;
        });
      }
      const d = { ...statusData };
      delete d.__STATUS;
      return d;
    },
    []
  );

  const saveRowFn = useCallback(
    (row: any) => {
      setInnerData((prev) => {
        const next = prev.map((item: any) =>
          getRowKey(item, rowKey) === getRowKey(row, rowKey)
            ? { ...row, __STATUS: ROW_STATUS.DEFAULT }
            : item
        );
        onRowSave?.(getPureData(next), getPureData(row));
        return next;
      });
    },
    [rowKey, onRowSave, getPureData]
  );

  const removeRowFn = useCallback(
    (row: any) => {
      setInnerData((prev) => {
        const next = prev.filter(
          (item: any) =>
            getRowKey(item, rowKey) !== getRowKey(row, rowKey)
        );
        onRowRemove?.(getPureData(next), getPureData(row));
        return next;
      });
    },
    [rowKey, onRowRemove, getPureData]
  );

  const editRowFn = useCallback(
    (row: any) => {
      setInnerData((prev) => {
        const next = prev.map((item: any) =>
          getRowKey(item, rowKey) === getRowKey(row, rowKey)
            ? { ...item, __STATUS: ROW_STATUS.EDITING }
            : item
        );
        onRowEdit?.(getPureData(next), getPureData(row));
        return next;
      });
    },
    [rowKey, onRowEdit, getPureData]
  );

  const cancelRowFn = useCallback(
    (row: any) => {
      const status = row.__STATUS;
      setInnerData((prev) => {
        let next: any[];
        if (status === ROW_STATUS.EDITING) {
          next = prev.map((item: any) =>
            getRowKey(item, rowKey) === getRowKey(row, rowKey)
              ? { ...item, __STATUS: ROW_STATUS.DEFAULT }
              : item
          );
        } else {
          next = prev.filter(
            (item: any) =>
              getRowKey(item, rowKey) !== getRowKey(row, rowKey)
          );
        }
        onRowCancel?.(getPureData(next), getPureData(row));
        return next;
      });
    },
    [rowKey, onRowCancel, getPureData]
  );

  const addRowFn = useCallback(() => {
    const defaultRow: any = {
      key: `${Date.now()}`,
    };
    if (showActionColumn) {
      defaultRow.__STATUS = propData
        ? ROW_STATUS.TEMPORARY
        : ROW_STATUS.NEW;
    }
    columns.forEach((col) => {
      if (col.dataIndex) defaultRow[col.dataIndex] = "";
    });
    setInnerData((prev) => {
      const next = [...prev, defaultRow];
      onRowAdd?.(getPureData(propData ? prev : next));
      return next;
    });
  }, [columns, showActionColumn, propData, onRowAdd, getPureData]);

  const allLeafColumns = useMemo(() => {
    const leafCols = getLeafColumns(columns);
    if (!showActionColumn) return leafCols;

    const actionCol: STableColumnProps = {
      title: actionColumnTitle || "操作",
      dataIndex: "__ACTION_COLUMN__",
      fixed: actionColumnFixed,
      width: 150,
      render: (_: any, row: any) => {
        const status = row.__STATUS;
        if (actionColumnRender) {
          return actionColumnRender(row, {
            status: status || "default",
            onSave: saveRowFn,
            onCancel: cancelRowFn,
            onEdit: editRowFn,
            onRemove: removeRowFn,
          });
        }
        if (
          status === ROW_STATUS.NEW ||
          status === ROW_STATUS.EDITING
        ) {
          return (
            <>
              <SaveWrapper
                render={(handleSave) => (
                  <TextButton onClick={() => handleSave(saveRowFn, row)}>
                    保存
                  </TextButton>
                )}
              />
              <TextButton onClick={() => cancelRowFn(row)}>取消</TextButton>
            </>
          );
        }
        return (
          <>
            <TextButton onClick={() => editRowFn(row)}>编辑</TextButton>
            <TextButton onClick={() => removeRowFn(row)}>删除</TextButton>
          </>
        );
      },
    };

    if (actionColumnFixed === "left") return [actionCol, ...leafCols];
    return [...leafCols, actionCol];
  }, [
    columns,
    showActionColumn,
    actionColumnFixed,
    actionColumnTitle,
    actionColumnRender,
    innerData,
    saveRowFn,
    removeRowFn,
    editRowFn,
    cancelRowFn,
  ]);

  const fullColumns = useMemo(() => {
    if (!showActionColumn) return columns;
    const actionCol: STableColumnProps = {
      title: actionColumnTitle || "操作",
      dataIndex: "__ACTION_COLUMN__",
      fixed: actionColumnFixed,
      width: 150,
    };
    if (actionColumnFixed === "left") return [actionCol, ...columns];
    return [...columns, actionCol];
  }, [columns, showActionColumn, actionColumnFixed, actionColumnTitle]);

  const headerRows = useMemo(() => getHeaderRows(fullColumns), [fullColumns]);

  const handleResizeStart = useCallback(
    (colIndex: number) => (_e: React.MouseEvent) => {
      const startX = _e.clientX;
      const col = allLeafColumns[colIndex];
      const colKey = col.dataIndex || col.key || String(colIndex);
      const startWidth =
        columnWidths[colKey] ||
        (typeof col.width === "number" ? col.width : 120);

      setResizeHighlight(colIndex);

      const onMouseMove = (e: MouseEvent) => {
        const diff = e.clientX - startX;
        const newWidth = Math.max(50, startWidth + diff);
        setColumnWidths((prev) => ({ ...prev, [colKey]: newWidth }));
      };

      const onMouseUp = () => {
        setResizeHighlight(null);
        document.removeEventListener("mousemove", onMouseMove);
        document.removeEventListener("mouseup", onMouseUp);
        document.body.style.userSelect = "";
        document.body.style.cursor = "";

        if (onResizeStop) {
          const updatedCols = allLeafColumns.map((c, i) => {
            const k = c.dataIndex || c.key || String(i);
            return { ...c, width: columnWidths[k] || c.width };
          });
          onResizeStop(updatedCols[colIndex], updatedCols);
        }
      };

      document.body.style.userSelect = "none";
      document.body.style.cursor = "col-resize";
      document.addEventListener("mousemove", onMouseMove);
      document.addEventListener("mouseup", onMouseUp);
    },
    [allLeafColumns, columnWidths, onResizeStop]
  );

  const getColumnWidth = useCallback(
    (col: STableColumnProps, index: number) => {
      const colKey = col.dataIndex || col.key || String(index);
      if (columnWidths[colKey]) return columnWidths[colKey];
      if (typeof col.width === "number") return col.width;
      if (typeof col.width === "string") return col.width;
      return undefined;
    },
    [columnWidths]
  );

  const getCellBorderStyle = useCallback(
    (colIndex: number, rowIndex: number, rowCount: number): CSSProperties => {
      const isLastCol = colIndex >= allLeafColumns.length - 1;
      const isLastRow = rowIndex >= rowCount - 1;
      const style: CSSProperties = {};
      if (!isLastRow) style.borderBottom = "1px solid var(--color-border-2)";
      if (borderCell && !isLastCol) {
        style.borderRight = "1px solid var(--color-border-2)";
      }
      return style;
    },
    [allLeafColumns.length, borderCell]
  );

  const getHeaderCellBorderStyle = useCallback(
    (endLeafIndex: number): CSSProperties => {
      const isLastLeafColumn = endLeafIndex >= allLeafColumns.length - 1;
      const style: CSSProperties = {
        borderBottom: "1px solid var(--color-border-2)",
      };
      if (borderCell && !isLastLeafColumn) {
        style.borderRight = "1px solid var(--color-border-2)";
      }
      return style;
    },
    [allLeafColumns.length, borderCell]
  );

  const tableWidth =
    scroll?.x ??
    allLeafColumns.reduce((sum, col, i) => {
      const w = getColumnWidth(col, i);
      return sum + (typeof w === "number" ? w : 120);
    }, 0);

  return (
    <div className={className} style={style}>
      <div
        ref={tableRef}
        style={{
          position: "relative",
          overflow: "hidden",
          border: "1px solid var(--color-border-2)",
          borderRadius: "var(--border-radius-small)",
          background: "var(--color-bg-1)",
        }}
      >
        <div
          style={{
            overflow: scroll ? "auto" : undefined,
            maxHeight: scroll?.y,
          }}
        >
          <table
            style={{
              width: "100%",
              minWidth: scroll?.x || "100%",
              borderCollapse: "separate",
              borderSpacing: 0,
              tableLayout: scroll?.x ? "fixed" : "auto",
              fontSize: 14,
              color: "var(--color-text-1)",
            }}
          >
            <colgroup>
              {allLeafColumns.map((col, i) => (
                <col
                  key={col.dataIndex || col.key || i}
                  style={{ width: getColumnWidth(col, i) }}
                />
              ))}
            </colgroup>
            <thead>
              {headerRows.map((row, rowIdx) => (
                <tr key={rowIdx}>
                  {row.map((cell, cellIdx) => (
                    <th
                      key={cell.col.dataIndex || cell.col.key || cellIdx}
                      colSpan={cell.colSpan > 1 ? cell.colSpan : undefined}
                      rowSpan={cell.rowSpan > 1 ? cell.rowSpan : undefined}
                      style={{
                        padding: "9px 16px",
                        textAlign: (cell.col.align as any) || "left",
                        fontWeight: 500,
                        fontSize: 14,
                        lineHeight: "22px",
                        color: "var(--color-text-2)",
                        background: "var(--color-bg-4)",
                        whiteSpace: "nowrap",
                        position: "relative",
                        ...getHeaderCellBorderStyle(cell.endLeafIndex),
                      }}
                    >
                      {cell.col.title}
                      {resizable &&
                        cell.rowSpan >= 1 &&
                        !cell.col.children &&
                        cell.endLeafIndex < allLeafColumns.length - 1 && (
                          <div
                            style={{
                              position: "absolute",
                              right: 0,
                              top: 0,
                              bottom: 0,
                              width: 6,
                              cursor: "col-resize",
                              zIndex: 10,
                            }}
                            onMouseDown={handleResizeStart(
                              allLeafColumns.findIndex(
                                (c) =>
                                  (c.dataIndex || c.key) ===
                                  (cell.col.dataIndex || cell.col.key)
                              )
                            )}
                            onMouseEnter={() => setResizerVisible(true)}
                            onMouseLeave={() => {
                              if (resizeHighlight === null)
                                setResizerVisible(false);
                            }}
                          >
                            <div
                              style={{
                                position: "absolute",
                                right: 0,
                                top: 0,
                                width: 2,
                                height: "100%",
                                backgroundColor:
                                  resizeHighlight ===
                                  allLeafColumns.findIndex(
                                    (c) =>
                                      (c.dataIndex || c.key) ===
                                      (cell.col.dataIndex || cell.col.key)
                                  )
                                    ? "rgb(var(--primary-6))"
                                    : "transparent",
                                transition: "background-color 0.15s",
                              }}
                            />
                          </div>
                        )}
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
            <tbody>
              {loading ? (
                <tr>
                  <td
                    colSpan={allLeafColumns.length}
                    style={{ padding: 40, textAlign: "center" }}
                  >
                    <div
                      style={{
                        display: "inline-block",
                        width: 20,
                        height: 20,
                        border: "2px solid rgb(var(--primary-6))",
                        borderTopColor: "transparent",
                        borderRadius: "50%",
                        animation: "s-table-spin 0.8s linear infinite",
                      }}
                    />
                  </td>
                </tr>
              ) : innerData.length === 0 ? (
                <tr>
                  <td
                    colSpan={allLeafColumns.length}
                    style={{ padding: 40, textAlign: "center" }}
                  >
                    {noDataElement || (
                      <div
                        style={{
                          color: "var(--color-text-3)",
                          fontSize: 14,
                        }}
                      >
                        暂无数据
                      </div>
                    )}
                  </td>
                </tr>
              ) : (
                paginatedData.map((record, rowIndex) => {
                  const rk = getRowKey(record, rowKey);
                  const isEditable = allLeafColumns.some((c) => c.editable);
                  const rowContent = allLeafColumns.map((col, colIndex) => {
                    const colKey = col.dataIndex || col.key || String(colIndex);
                    const value = col.dataIndex ? record[col.dataIndex] : undefined;
                    const cellContent = col.render
                      ? col.render(value, record, rowIndex)
                      : value;

                    return (
                      <td
                        key={colKey}
                        style={{
                          padding: col.editable ? "4px 8px" : "9px 16px",
                          textAlign: (col.align as any) || "left",
                          fontSize: 14,
                          lineHeight: "22px",
                          background:
                            hoverRow === rk && hover
                              ? "var(--color-bg-4)"
                              : stripe && rowIndex % 2 === 1
                              ? "var(--color-bg-4)"
                              : "var(--color-bg-1)",
                          transition: "background 0.2s",
                          ...getCellBorderStyle(
                            colIndex,
                            rowIndex,
                            paginatedData.length
                          ),
                        }}
                      >
                        {col.editable ? (
                          <EditableCell
                            rowData={record}
                            column={col}
                            onSave={saveRowFn}
                            rowStatus={record.__STATUS}
                          >
                            {cellContent}
                          </EditableCell>
                        ) : (
                          cellContent
                        )}
                      </td>
                    );
                  });

                  const row = isEditable ? (
                    <EditableRow key={rk} record={record} columns={allLeafColumns}>
                      {rowContent}
                    </EditableRow>
                  ) : (
                    <tr
                      key={rk}
                      onMouseEnter={() => setHoverRow(rk)}
                      onMouseLeave={() => setHoverRow(null)}
                      style={{ transition: "background 0.2s" }}
                    >
                      {rowContent}
                    </tr>
                  );

                  return row;
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showPagination && (
        <div style={{ display: "flex", justifyContent: "flex-end", padding: "12px 0" }}>
          <Pagination>
            <PaginationContent>
              <PaginationItem>
                <PaginationPrevious
                  onClick={(e) => {
                    e.preventDefault();
                    setCurrentPage((p) => Math.max(1, p - 1));
                  }}
                  style={{
                    pointerEvents: currentPage <= 1 ? "none" : undefined,
                    opacity: currentPage <= 1 ? 0.5 : 1,
                  }}
                />
              </PaginationItem>
              {getPageNumbers(currentPage, totalPages).map((page, i) =>
                page === "ellipsis" ? (
                  <PaginationItem key={`ellipsis-${i}`}>
                    <PaginationEllipsis />
                  </PaginationItem>
                ) : (
                  <PaginationItem key={page}>
                    <PaginationLink
                      isActive={page === currentPage}
                      onClick={(e) => {
                        e.preventDefault();
                        setCurrentPage(page as number);
                      }}
                    >
                      {page}
                    </PaginationLink>
                  </PaginationItem>
                )
              )}
              <PaginationItem>
                <PaginationNext
                  onClick={(e) => {
                    e.preventDefault();
                    setCurrentPage((p) => Math.min(totalPages, p + 1));
                  }}
                  style={{
                    pointerEvents: currentPage >= totalPages ? "none" : undefined,
                    opacity: currentPage >= totalPages ? 0.5 : 1,
                  }}
                />
              </PaginationItem>
            </PaginationContent>
          </Pagination>
        </div>
      )}

      {addRowBtn && (
        <AddRowButton
          customBtn={addRowBtn !== true ? addRowBtn : undefined}
          text={addRowBtnText}
          icon={addRowBtnIcon}
          disabled={!!(maxDataLength && maxDataLength <= innerData.length)}
          onAddRow={addRowFn}
        />
      )}

      <style>{`
        @keyframes s-table-spin {
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

const STableExport = Object.assign(STable, {
  EditableSaveWrapper: SaveWrapper,
});

export type {
  STableProps,
  STableColumnProps,
  ActionColumnRenderOptions,
};
export { SaveWrapper };
export default STableExport;
